// C# — Binary Tree: Insert, Search, Delete, Traversals, Height, Size
using System.Collections.Generic;

public class TreeNode
{
    public int Data;
    public TreeNode? Left, Right;
    public TreeNode(int data) { Data = data; }
}

public class BinaryTree
{
    private TreeNode? root;

    // Insert — level-order (BFS) to keep tree complete
    public void Insert(int data)
    {
        var newNode = new TreeNode(data);
        if (root is null) { root = newNode; return; }
        var queue = new Queue<TreeNode>();
        queue.Enqueue(root);
        while (queue.Count > 0)
        {
            var current = queue.Dequeue();
            if (current.Left is null) { current.Left = newNode; return; }
            else queue.Enqueue(current.Left);
            if (current.Right is null) { current.Right = newNode; return; }
            else queue.Enqueue(current.Right);
        }
    }

    // Search — BFS to find a value
    public bool Search(int target)
    {
        if (root is null) return false;
        var queue = new Queue<TreeNode>();
        queue.Enqueue(root);
        while (queue.Count > 0)
        {
            var current = queue.Dequeue();
            if (current.Data == target) return true;
            if (current.Left is not null) queue.Enqueue(current.Left);
            if (current.Right is not null) queue.Enqueue(current.Right);
        }
        return false;
    }

    // Delete — replace target with deepest rightmost node
    public void Delete(int target)
    {
        if (root is null) return;
        TreeNode? targetNode = null;
        TreeNode? parent = null;
        TreeNode? deepest = null;
        var queue = new Queue<TreeNode>();
        queue.Enqueue(root);
        while (queue.Count > 0)
        {
            deepest = queue.Dequeue();
            if (deepest.Data == target) targetNode = deepest;
            if (deepest.Left is not null) { parent = deepest; queue.Enqueue(deepest.Left); }
            if (deepest.Right is not null) { parent = deepest; queue.Enqueue(deepest.Right); }
        }
        if (targetNode is not null && deepest is not null)
        {
            targetNode.Data = deepest.Data;
            if (parent?.Right == deepest) parent.Right = null;
            else if (parent?.Left == deepest) parent.Left = null;
        }
    }

    // Inorder Traversal — Left, Root, Right
    public void Inorder(TreeNode? node)
    {
        if (node is null) return;
        Inorder(node.Left);
        Console.Write(node.Data + " ");
        Inorder(node.Right);
    }

    // Preorder Traversal — Root, Left, Right
    public void Preorder(TreeNode? node)
    {
        if (node is null) return;
        Console.Write(node.Data + " ");
        Preorder(node.Left);
        Preorder(node.Right);
    }

    // Postorder Traversal — Left, Right, Root
    public void Postorder(TreeNode? node)
    {
        if (node is null) return;
        Postorder(node.Left);
        Postorder(node.Right);
        Console.Write(node.Data + " ");
    }

    // Get Height — longest path from root to leaf
    public int GetHeight(TreeNode? node)
    {
        if (node is null) return -1;
        return 1 + Math.Max(GetHeight(node.Left), GetHeight(node.Right));
    }

    // Get Size — total number of nodes
    public int GetSize(TreeNode? node)
    {
        if (node is null) return 0;
        return 1 + GetSize(node.Left) + GetSize(node.Right);
    }
}

