    TreeNode *left, *right;
    TreeNode(int d) : data(d), left(nullptr), right(nullptr) {}
};

class BinaryTree {
    TreeNode* root = nullptr;
public:
    void insert(int data) {
        TreeNode* newNode = new TreeNode(data);
        if (!root) { root = newNode; return; }
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            TreeNode* cur = q.front(); q.pop();
            if (!cur->left) { cur->left = newNode; return; }
            else q.push(cur->left);
            if (!cur->right) { cur->right = newNode; return; }
            else q.push(cur->right);
        }
    }

    bool search(int target) {
        if (!root) return false;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            TreeNode* cur = q.front(); q.pop();
            if (cur->data == target) return true;
            if (cur->left) q.push(cur->left);
            if (cur->right) q.push(cur->right);
        }
        return false;
    }

    void deleteNode(int target) {
        if (!root) return;
        TreeNode* targetNode = nullptr;
        TreeNode* parent = nullptr;
        TreeNode* deepest = nullptr;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            deepest = q.front(); q.pop();
            if (deepest->data == target) targetNode = deepest;
            if (deepest->left) { parent = deepest; q.push(deepest->left); }
            if (deepest->right) { parent = deepest; q.push(deepest->right); }
        }
        if (targetNode) {
            targetNode->data = deepest->data;
            if (parent->right == deepest) parent->right = nullptr;
            else parent->left = nullptr;
