        if (!node) return;
        postorder(node->left);
        postorder(node->right);
        cout << node->data << " ";
    }

    int getHeight(TreeNode* node) {
        if (!node) return -1;
        return 1 + max(getHeight(node->left), getHeight(node->right));
    }

    int getSize(TreeNode* node) {
