// Java — Binary Tree: Insert, Search, Delete, Traversals, Height, Size
import java.util.LinkedList;
import java.util.Queue;

class TreeNode {
    int data;
    TreeNode left, right;
    TreeNode(int data) { this.data = data; }
}

public class BinaryTree {
    private TreeNode root;

    public void insert(int data) {
        TreeNode newNode = new TreeNode(data);
        if (root == null) { root = newNode; return; }
        Queue<TreeNode> queue = new LinkedList<>();
        queue.add(root);
        while (!queue.isEmpty()) {
            TreeNode cur = queue.poll();
            if (cur.left == null) { cur.left = newNode; return; }
            else queue.add(cur.left);
            if (cur.right == null) { cur.right = newNode; return; }
            else queue.add(cur.right);
        }
    }

    public boolean search(int target) {
        if (root == null) return false;
        Queue<TreeNode> queue = new LinkedList<>();
        queue.add(root);
        while (!queue.isEmpty()) {
            TreeNode cur = queue.poll();
            if (cur.data == target) return true;
            if (cur.left != null) queue.add(cur.left);
            if (cur.right != null) queue.add(cur.right);
        }
        return false;
    }

    public void delete(int target) {
        if (root == null) return;
        TreeNode targetNode = null, parent = null, deepest = null;
        Queue<TreeNode> queue = new LinkedList<>();
        queue.add(root);
        while (!queue.isEmpty()) {
            deepest = queue.poll();
            if (deepest.data == target) targetNode = deepest;
            if (deepest.left != null) { parent = deepest; queue.add(deepest.left); }
            if (deepest.right != null) { parent = deepest; queue.add(deepest.right); }
        }
        if (targetNode != null) {
            targetNode.data = deepest.data;
            if (parent.right == deepest) parent.right = null;
            else parent.left = null;
        }
    }

    public void inorder(TreeNode node) {
        if (node == null) return;
        inorder(node.left);
        System.out.print(node.data + " ");
        inorder(node.right);
    }

    public void preorder(TreeNode node) {
        if (node == null) return;
        System.out.print(node.data + " ");
        preorder(node.left);
        preorder(node.right);
    }

    public void postorder(TreeNode node) {
        if (node == null) return;
        postorder(node.left);
        postorder(node.right);
        System.out.print(node.data + " ");
    }

    public int getHeight(TreeNode node) {
        if (node == null) return -1;
        return 1 + Math.max(getHeight(node.left), getHeight(node.right));
    }

    public int getSize(TreeNode node) {
        if (node == null) return 0;
        return 1 + getSize(node.left) + getSize(node.right);
    }

    public static void main(String[] args) {
        BinaryTree tree = new BinaryTree();
        tree.insert(1); tree.insert(2); tree.insert(3);
        tree.insert(4); tree.insert(5);
        tree.inorder(tree.root);   // 4 2 5 1 3
        tree.preorder(tree.root);  // 1 2 4 5 3
        tree.postorder(tree.root); // 4 5 2 3 1
        boolean found = tree.search(3); // true
    }
}

// JavaScript — Binary Tree: Insert, Search, Delete, Traversals, Height, Size

class TreeNode {
    constructor(data) {
        this.data = data;
        this.left = null;
        this.right = null;
    }
}

class BinaryTree {
    constructor() { this.root = null; }

    // Insert — level-order BFS
    insert(data) {
        const newNode = new TreeNode(data);
        if (!this.root) { this.root = newNode; return; }
        const queue = [this.root];
        while (queue.length > 0) {
            const cur = queue.shift();
            if (!cur.left) { cur.left = newNode; return; }
            else queue.push(cur.left);
            if (!cur.right) { cur.right = newNode; return; }
            else queue.push(cur.right);
        }
    }

    // Search — BFS
    search(target) {
        if (!this.root) return false;
        const queue = [this.root];
        while (queue.length > 0) {
            const cur = queue.shift();
            if (cur.data === target) return true;
            if (cur.left) queue.push(cur.left);
            if (cur.right) queue.push(cur.right);
        }
        return false;
    }

    // Delete — replace with deepest rightmost node
    delete(target) {
        if (!this.root) return;
        let targetNode = null, parent = null, deepest = null;
        const queue = [this.root];
        while (queue.length > 0) {
            deepest = queue.shift();
            if (deepest.data === target) targetNode = deepest;
            if (deepest.left) { parent = deepest; queue.push(deepest.left); }
            if (deepest.right) { parent = deepest; queue.push(deepest.right); }
        }
        if (targetNode) {
            targetNode.data = deepest.data;
            if (parent.right === deepest) parent.right = null;
            else parent.left = null;
        }
    }

    // Inorder — Left, Root, Right
    inorder(node = this.root) {
        if (!node) return;
        this.inorder(node.left);
        process.stdout.write(node.data + ' ');
        this.inorder(node.right);
    }

    // Preorder — Root, Left, Right
    preorder(node = this.root) {
        if (!node) return;
        process.stdout.write(node.data + ' ');
        this.preorder(node.left);
        this.preorder(node.right);
    }

    // Postorder — Left, Right, Root
    postorder(node = this.root) {
        if (!node) return;
        this.postorder(node.left);
        this.postorder(node.right);
        process.stdout.write(node.data + ' ');
    }

    // Get Height
    getHeight(node = this.root) {
        if (!node) return -1;
        return 1 + Math.max(this.getHeight(node.left), this.getHeight(node.right));
    }

    // Get Size
    getSize(node = this.root) {
        if (!node) return 0;
        return 1 + this.getSize(node.left) + this.getSize(node.right);
    }
}

